const designImportMigration=require("../../../../../../design_import_migration");const lotusscriptUtils=designImportMigration.getMxgoUtils().moduleFunctions.lotusscriptUtils;const _kgb_=designImportMigration.getMxgoUtils().getKgbGlobal();class ActionBarBtnLssSnippet{getId(t){let s=[];s.push(t);s.push(_kgb_.modules.utils.getKUID().toString());return s.join("_")}constructor(){this.setDefault()}setDefault(){this.addSnippetAction={id:this.getId("ADD_LOTUSSCRIPT"),codeSnippet:"alert('test')",lotusscripts:{},type:"ADD_LOTUSSCRIPT"}}setAddSnippetCode(t){var s="";var i="";if(t.convertedLotuscript){s=t.convertedLotuscript}if(t.lotusscript){i=t.lotusscript}var e=lotusscriptUtils.generateNewLotusscriptId();var o=lotusscriptUtils.generatedLotusscriptCode(e,s);this.addSnippetAction.codeSnippet="try {\n"+o+"\n} catch(e) { \n console.log(e); alert(e); \n}";this.addSnippetAction.lotusscripts[e]=i}toActions(){return[this.addSnippetAction]}}module.exports={ActionBarBtnLssSnippet:ActionBarBtnLssSnippet};